export function buildKKClinics(): Clinic[] {
  return KK_RAW.map((r) => ({
    id: r.id,
    name: r.name,
    address: r.address,
    state: r.state,
    distanceKm: 0,
    waitMinutes: r.waitMinutes,
    queueLength: r.queueLength,
    queueLoad: r.queueLoad,
    emergency: r.emergency,
    driveMinutes: Math.round(r.waitMinutes * 0.6),
    walkMinutes: Math.round(r.waitMinutes * 6),
    lat: r.lat,
    lng: r.lng,
    x: 50,
    y: 50,
  }));
}
